module top_module(
    input [7:0] in1,
    input [7:0] in2,
    input reset,
    output reg [7:0] sum, // Change to reg type
    output reg overflow    // Change to reg type
);reg [8:0] sum_temp;

always @(*) begin
    if (reset) begin
        sum_temp = 0;
        overflow = 0;
    end else begin
        sum_temp = {1'b0, in1} + {1'b0, in2};
        overflow = sum_temp[8];
    end
end

assign sum = sum_temp[7:0];

endmodule
